(game "Simple Capture"
    (players 2)
    (equipment 
        (board (square 4))
    ) 

    (rules 
        (start
            (place P1 (1 1))
            (place P2 (3 3))
        )
        (play
            (repeat (P1 P2)
                (place 
                    (destination empty)
                    (effects 
                        (capture (adjacent occupied) increment_score:true)
                    )
                )
            )
        )
        (end 
            (if (>= (score mover) 2) (mover win))
            (if (full_board) (draw))    
        )
    )
    (rendering
        (color P1 black)
        (color P2 white)
    )
)

