(game "Island Hoppers"
    (players 2)
    (equipment 
        (board (square 5))
    ) 

    (rules 
        (play
            (repeat (P1 P2)
                (place (destination empty))
            )
        )

        (end 
            (if (and (connected (edges)) (mover_is P1)) (mover win))
            (if (and (connected (edges)) (mover_is P2)) (mover win))
            (if (full_board) (draw))    
        )
    )
    (rendering
        (color P1 black)
        (color P2 white)
    )
)
